import numpy as np

class RAGPipeline:
    def __init__(self):
        self._ids = []
        self._texts = {}
        self._embeddings = []

    def add_document(self, doc_id: str, text: str, embedding: np.ndarray):
        self._ids.append(doc_id)
        self._texts[doc_id] = text
        self._embeddings.append(embedding.astype(np.float32))

    def retrieve(self, query_embedding: np.ndarray, top_k: int) -> tuple:
        if not self._ids:
            raise ValueError('No documents in pipeline')
        E = np.array(self._embeddings)
        q = query_embedding.astype(np.float32)
        q_norm = q / (np.linalg.norm(q) + 1e-8)
        E_norm = E / (np.linalg.norm(E, axis=1, keepdims=True) + 1e-8)
        scores = E_norm @ q_norm
        top_k = min(top_k, len(self._ids))
        top_idx = np.argsort(scores)[::-1][:top_k]
        return [self._ids[i] for i in top_idx], [float(scores[i]) for i in top_idx]

    def format_context(self, doc_ids: list, query: str) -> str:
        parts = [f'Query: {query}', 'Context:']
        for i, did in enumerate(doc_ids, 1):
            parts.append(f'[{i}] {self._texts[did]}')
        return '\n'.join(parts)

    def rag_query(self, query_embedding: np.ndarray, query_text: str, top_k: int) -> str:
        doc_ids, _ = self.retrieve(query_embedding, top_k)
        return self.format_context(doc_ids, query_text)
